        protected override void OnConfiguring(DbContextOptionsBuilder optionsBuilder)
        {

        }

        protected override void OnModelCreating(ModelBuilder modelBuilder)
        {
            base.OnModelCreating(modelBuilder);

            modelBuilder.Entity<APAddress>(entity =>
            {
                entity.HasIndex(e => new { e.APIP, e.CompanyNo })
                    .HasName("IX_APAddress")
                    .IsUnique();

                entity.Property(e => e.Id)
                    .HasColumnType("numeric(18, 0)")
                    .HasComment("PK")
                    .ValueGeneratedOnAdd();

                entity.Property(e => e.APIP)
                    .IsRequired()
                    .HasMaxLength(20)
                    .IsUnicode(false);

                entity.Property(e => e.CompanyNo)
                    .IsRequired()
                    .HasMaxLength(50)
                    .IsUnicode(false)
                    .HasComment("公司別");

                entity.Property(e => e.PDFPort)
                    .HasMaxLength(10)
                    .IsUnicode(false);

                entity.Property(e => e.msrepl_tran_version).HasDefaultValueSql("(newid())");
            });

            modelBuilder.Entity<APMonth>(entity =>
            {
                entity.HasKey(e => new { e.Id, e.LocaleId });

                entity.Property(e => e.Id).HasColumnType("numeric(18, 0)");

                entity.Property(e => e.LocaleId).HasColumnType("numeric(18, 0)");

                entity.Property(e => e.AP).HasColumnType("numeric(18, 4)");

                entity.Property(e => e.APGet).HasColumnType("numeric(18, 4)");

                entity.Property(e => e.APGetPre).HasColumnType("numeric(18, 4)");

                entity.Property(e => e.APNo)
                    .IsRequired()
                    .HasMaxLength(30)
                    .IsUnicode(false);

                entity.Property(e => e.APTTL).HasColumnType("numeric(18, 4)");

                entity.Property(e => e.BankingRate)
                    .HasColumnType("numeric(18, 6)")
                    .HasDefaultValueSql("((1))");

                entity.Property(e => e.CloseTime).HasColumnType("datetime");

                entity.Property(e => e.CloseUserName)
                    .HasMaxLength(50)
                    .IsUnicode(false);

                entity.Property(e => e.Discount).HasColumnType("numeric(18, 4)");

                entity.Property(e => e.DollarCodeName)
                    .IsRequired()
                    .HasMaxLength(30)
                    .IsUnicode(false)
                    .HasDefaultValueSql("('NTD')");

                entity.Property(e => e.ISONo)
                    .HasMaxLength(20)
                    .IsUnicode(false);

                entity.Property(e => e.LastUpdateTime).HasColumnType("datetime");

                entity.Property(e => e.ModifyUserName)
                    .IsRequired()
                    .HasMaxLength(50)
                    .IsUnicode(false);

                entity.Property(e => e.PaymentCodeName)
                    .HasMaxLength(30)
                    .IsUnicode(false);

                entity.Property(e => e.PreAPTTL).HasColumnType("numeric(18, 4)");

                entity.Property(e => e.ReceiveAddress).HasMaxLength(255);

                entity.Property(e => e.Remark).HasMaxLength(128);

                entity.Property(e => e.Tax).HasColumnType("numeric(18, 4)");

                entity.Property(e => e.TaxRate).HasColumnType("numeric(18, 2)");

                entity.Property(e => e.TelNo)
                    .HasMaxLength(50)
                    .IsUnicode(false);

                entity.Property(e => e.VendorNameTw)
                    .IsRequired()
                    .HasMaxLength(50)
                    .IsUnicode(false);

                entity.Property(e => e.YYYYMM)
                    .IsRequired()
                    .HasMaxLength(6)
                    .IsUnicode(false);
                entity.Property(e => e.PaymentLocaleId).HasColumnType("numeric(18, 0)");
                entity.Property(e => e.msrepl_tran_version).HasDefaultValueSql("(newid())");
            });

            modelBuilder.Entity<APMonthInvoice>(entity =>
            {
                entity.HasKey(e => new { e.Id, e.LocaleId });

                entity.Property(e => e.Id)
                    .HasColumnType("numeric(18, 0)")
                    .ValueGeneratedOnAdd();

                entity.Property(e => e.LocaleId).HasColumnType("numeric(18, 0)");

                entity.Property(e => e.APMonthId).HasColumnType("numeric(18, 0)");

                entity.Property(e => e.BankingRate)
                    .HasColumnType("numeric(18, 6)")
                    .HasDefaultValueSql("((1))");

                entity.Property(e => e.InvoiceAmount).HasColumnType("numeric(18, 2)");

                entity.Property(e => e.InvoiceAmountTTL).HasColumnType("numeric(18, 2)");

                entity.Property(e => e.InvoiceDate).HasColumnType("datetime");

                entity.Property(e => e.InvoiceNo)
                    .IsRequired()
                    .HasMaxLength(30)
                    .IsUnicode(false);

                entity.Property(e => e.InvoiceTax).HasColumnType("numeric(18, 2)");

                entity.Property(e => e.Remark).HasMaxLength(50);

                entity.Property(e => e.VoucherNo)
                    .HasMaxLength(20)
                    .IsUnicode(false);

                entity.Property(e => e.msrepl_tran_version).HasDefaultValueSql("(newid())");
            });

            modelBuilder.Entity<APMonthItem>(entity =>
            {
                entity.HasKey(e => new { e.Id, e.LocaleId });

                entity.Property(e => e.Id)
                    .HasColumnType("numeric(18, 0)")
                    .ValueGeneratedOnAdd();

                entity.Property(e => e.LocaleId).HasColumnType("numeric(18, 0)");

                entity.Property(e => e.APAmount).HasColumnType("numeric(18, 4)");

                entity.Property(e => e.APGet).HasColumnType("numeric(18, 4)");

                entity.Property(e => e.APMonthId).HasColumnType("numeric(18, 0)");

                entity.Property(e => e.APTTL).HasColumnType("numeric(18, 4)");

                entity.Property(e => e.APTax).HasColumnType("numeric(18, 4)");

                entity.Property(e => e.APYM)
                    .IsRequired()
                    .HasMaxLength(6)
                    .IsUnicode(false);

                entity.Property(e => e.BankingRate)
                    .HasColumnType("numeric(18, 6)")
                    .HasDefaultValueSql("((1))");

                entity.Property(e => e.Discount).HasColumnType("numeric(18, 4)");

                entity.Property(e => e.DollarCodeName)
                    .HasMaxLength(30)
                    .IsUnicode(false);

                entity.Property(e => e.PUnit)
                    .HasMaxLength(20)
                    .IsUnicode(false);

                entity.Property(e => e.PayQty).HasColumnType("numeric(18, 2)");

                entity.Property(e => e.PreAPGet).HasColumnType("numeric(18, 4)");

                entity.Property(e => e.PurLocaleId).HasColumnType("numeric(18, 0)");

                entity.Property(e => e.POItemId).HasColumnType("numeric(18, 0)");

                entity.Property(e => e.ReceivedLocaleId).HasColumnType("numeric(18, 0)");

                entity.Property(e => e.ReceivedLogId).HasColumnType("numeric(18, 0)");

                // entity.Property(e => e.PaymentLocaleId).HasColumnType("numeric(18, 0)");

                entity.Property(e => e.PurUserName)
                    .HasMaxLength(50)
                    .IsUnicode(false);

                entity.Property(e => e.ReceiveDate).HasColumnType("datetime");

                entity.Property(e => e.ReceiveRefNo)
                    .HasMaxLength(30)
                    .IsUnicode(false);

                entity.Property(e => e.Remark).HasMaxLength(50);

                entity.Property(e => e.SeqNo)
                    .HasMaxLength(4)
                    .IsUnicode(false);

                entity.Property(e => e.Spec)
                    .HasMaxLength(30)
                    .IsUnicode(false);

                entity.Property(e => e.TaxRate)
                    .HasColumnType("numeric(18, 2)")
                    .HasDefaultValueSql("((0.05))");

                entity.Property(e => e.TypeNo).HasMaxLength(512);

                entity.Property(e => e.UniInvoiceNo)
                    .HasMaxLength(10)
                    .IsUnicode(false);

                entity.Property(e => e.UnitPrice).HasColumnType("numeric(18, 8)");

                entity.Property(e => e.VendorMaterialNo)
                    .HasMaxLength(128)
                    .IsUnicode(false);

                entity.Property(e => e.VoucherNo)
                    .HasMaxLength(20)
                    .IsUnicode(false);

                entity.Property(e => e.WONo)
                    .HasMaxLength(30)
                    .IsUnicode(false);

                entity.Property(e => e.WarehouseNo)
                    .HasMaxLength(20)
                    .IsUnicode(false);

                entity.Property(e => e.msrepl_tran_version).HasDefaultValueSql("(newid())");
            });

            modelBuilder.Entity<APMonthItemDiscount>(entity =>
            {
                entity.HasKey(e => new { e.Id, e.LocaleId });

                entity.Property(e => e.Id)
                    .HasColumnType("numeric(18, 0)")
                    .ValueGeneratedOnAdd();

                entity.Property(e => e.LocaleId).HasColumnType("numeric(18, 0)");

                entity.Property(e => e.APAmount)
                    .HasColumnType("numeric(18, 4)")
                    .HasDefaultValueSql("((0))")
                    .HasComment("收貨應付金額");

                entity.Property(e => e.APGet)
                    .HasColumnType("numeric(18, 4)")
                    .HasDefaultValueSql("((0))")
                    .HasComment("付出金額(NTD)");

                entity.Property(e => e.APMonthId)
                    .HasColumnType("numeric(18, 0)")
                    .HasComment("月應收PK(ref.APMonth.Id)");

                entity.Property(e => e.APTTL)
                    .HasColumnType("numeric(18, 4)")
